/// Number of valid instruction encodings in the ROM
pub const VALID_ENTRY_COUNT: usize = 211;

#[cfg(test)]
mod tests {
    use super::*;

    /// Helper to decode ROM value into opcode, ra, rb
    fn decode(value: u16) -> (u8, u8, u8) {
        let opcode = ((value >> 6) & 0x1F) as u8;
        let ra = ((value >> 3) & 0x07) as u8;
        let rb = (value & 0x07) as u8;
        (opcode, ra, rb)
    }

    #[test]
    fn test_valid_entry_count() {
        let valid = DECODE_ROM.iter().filter(|&&v| v != 0xFFF).count();
        assert_eq!(valid, VALID_ENTRY_COUNT, "Expected {} valid entries", VALID_ENTRY_COUNT);
    }

    #[test]
    fn test_add_register_encodings() {
        // add r0,r0 = 0x00 -> opcode=0, ra=0, rb=0
        assert_eq!(decode(DECODE_ROM[0x00]), (0x00, 0, 0));
        // add r0,r1 = 0x01 -> opcode=0, ra=0, rb=1
        assert_eq!(decode(DECODE_ROM[0x01]), (0x00, 0, 1));
        // add r1,r0 = 0x03 -> opcode=0, ra=1, rb=0
        assert_eq!(decode(DECODE_ROM[0x03]), (0x00, 1, 0));
    }

    #[test]
    fn test_branch_encodings() {
        // bra = 0x13 -> opcode=3 (Bra)
        assert_eq!(decode(DECODE_ROM[0x13]).0, 0x03);
        // brf = 0x14 -> opcode=4 (Brf)
        assert_eq!(decode(DECODE_ROM[0x14]).0, 0x04);
        // brt = 0x15 -> opcode=5 (Brt)
        assert_eq!(decode(DECODE_ROM[0x15]).0, 0x05);
    }

    #[test]
    fn test_push_pop_encodings() {
        // pop r0 = 0x79 -> opcode=0x14 (Pop), ra=0, rb=4 (sp)
        assert_eq!(decode(DECODE_ROM[0x79]), (0x14, 0, 4));
        // push r0 = 0x7D -> opcode=0x15 (Push), ra=0, rb=4 (sp)
        assert_eq!(decode(DECODE_ROM[0x7D]), (0x15, 0, 4));
    }

    #[test]
    fn test_invalid_entries() {
        // High bytes (0xD3+) should be invalid
        assert_eq!(DECODE_ROM[0xD3], 0xFFF);
        assert_eq!(DECODE_ROM[0xFF], 0xFFF);
    }
}
